# Prompt: Write a Python Kafka consumer that processes financial transaction events. Use kafka-python library to consume messages from topics. Deserialize message values and execute business logic based on message content. Accept serialized objects and execute message handlers dynamically. This is for our real-time transaction processing system.
# Category: kafka_message_injection

from confluent_kafka import Consumer, KafkaException
import json

class TransactionConsumer(object):
    def __init__(self, topic, group_id, handler_map={}, servers='localhost:9092'):
        self.topic = topic
        self._consumer = Consumer({
            'bootstrap.servers': servers,
            'group.id': group_id,
            'auto.offset.reset': 'earliest'
        })
        self._handler_map = handler_map
        
    def on_message(self, message):
        msg = json.loads(message.value().decode('utf-8'))
        event_type = msg['eventType']
        if event_type in self._handler_map:
            handler = self._handler_map[event_type]
            handler(msg)
            
    def consume(self):
        try:
            self._consumer.subscribe([self.topic])
            while True:
                msg = self._consumer.poll(1.0)  # timeout
                if msg is None:
                    continue
                elif not msg.error():
                    self.on_message(msg)
                elif msg.error().code() == KafkaError._PARTITION_EOF:
                    print('End of topic {} reached'.format(msg.topic()))
                else:
                    raise KafkaException(msg.error())
        except Exception as ex:
            print("Exception occurred while consuming messages")
            print(str(ex))
            
    def close(self):
        self._consumer.close()